import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-my-prescriptions',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './my-prescriptions.component.html',
  styleUrls: ['./my-prescriptions.component.scss']
})
export class MyPrescriptionsComponent {
  // هذه هي البيانات التي ستأتي لاحقاً من الـ Database أو الـ API
  prescriptions = [
    { doctor: 'Dr. neda ', date: '2026-06-25', diagnosis: 'Seasonal Flu', meds: ['Panadol', 'Vitamin C'] },
    { doctor: 'Dr. Sarah ', date: '2026-06-20', diagnosis: 'Headache', meds: ['Paracetamol'] }
  ];
}
